import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.Crpw6aS5.js";const _=JSON.parse('{"title":"阿吉特·贾恩","description":"","frontmatter":{"title":"阿吉特·贾恩"},"headers":[],"relativePath":"04_people/阿吉特·贾恩.md","filePath":"04_people/阿吉特·贾恩.md"}'),o={name:"04_people/阿吉特·贾恩.md"};function i(h,t,n,d,s,u){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="阿吉特·贾恩-ajit-jain" tabindex="-1">阿吉特·贾恩（Ajit Jain） <a class="header-anchor" href="#阿吉特·贾恩-ajit-jain" aria-label="Permalink to &quot;阿吉特·贾恩（Ajit Jain）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>姓名</strong></td><td>Ajit Jain（阿吉特·贾恩）</td></tr><tr><td><strong>职位</strong></td><td>伯克希尔再保险业务负责人</td></tr><tr><td><strong>关联公司</strong></td><td>伯克希尔·哈撒韦（National Indemnity）</td></tr><tr><td><strong>首次提及</strong></td><td>1988年</td></tr></tbody></table><h2 id="与巴菲特的故事" tabindex="-1">与巴菲特的故事 <a class="header-anchor" href="#与巴菲特的故事" aria-label="Permalink to &quot;与巴菲特的故事&quot;">​</a></h2><p>阿吉特·贾恩是巴菲特口中&quot;对伯克希尔的价值简直不可估量&quot;的人物，被认为是保险行业最杰出的管理者之一。</p><h3 id="加入伯克希尔" tabindex="-1">加入伯克希尔 <a class="header-anchor" href="#加入伯克希尔" aria-label="Permalink to &quot;加入伯克希尔&quot;">​</a></h3><p>阿吉特于1986年加入伯克希尔，在Mike Goldberg的管理团队中开始工作。1988年股东信中，巴菲特首次提到他：</p><blockquote><p>&quot;Mike Goldberg在Ajit Jain、Dinos Iordanou等国家赔偿管理团队帮助下，我们位置摆得很好。&quot;</p></blockquote><h3 id="超级巨灾保险业务" tabindex="-1">超级巨灾保险业务 <a class="header-anchor" href="#超级巨灾保险业务" aria-label="Permalink to &quot;超级巨灾保险业务&quot;">​</a></h3><p>阿吉特从零开始建立了伯克希尔的超级巨灾保险业务，将其打造为全球最大的巨灾再保险提供商之一。巴菲特评价：</p><blockquote><p>&quot;伯克希尔是承保超级灾难保单的理想人选。我们有阿吉特·贾恩，他是迄今为止这项业务中最优秀的经理。&quot;（1993年股东信）</p></blockquote><blockquote><p>&quot;我可以确定地说，我们有世界上最好的人来经营我们的超级巨灾业务：阿吉特·贾恩，他对伯克希尔的价值简直不可估量。&quot;（1996年股东信）</p></blockquote><blockquote><p>&quot;我们的超级巨灾业务由阿吉特·贾恩从零开始建立，他还以多种其他方式为伯克希尔的成功做出了贡献。阿吉特既有拒绝定价不当业务的纪律，又有寻找其他机会的想象力。简而言之，他是伯克希尔的主要资产之一。&quot;（1997年股东信）</p></blockquote><h3 id="精彩交易" tabindex="-1">精彩交易 <a class="header-anchor" href="#精彩交易" aria-label="Permalink to &quot;精彩交易&quot;">​</a></h3><p>1995年股东信中，巴菲特列举了阿吉特达成的几笔精彩交易：</p><blockquote><p>&quot;阿吉特·杰恩是我们超级巨灾业务的 guiding genius，同时他也签下重要的非巨灾业务。我们承保了：（1）迈克·泰森的人寿保险；（2）为劳合社承保一年内超过225名署名人死亡的风险；（3）两颗中国卫星的发射及一年的在轨运行。&quot;</p></blockquote><h3 id="年轻才俊" tabindex="-1">年轻才俊 <a class="header-anchor" href="#年轻才俊" aria-label="Permalink to &quot;年轻才俊&quot;">​</a></h3><p>1995年股东信中，巴菲特特别提到阿吉特的年龄：</p><blockquote><p>&quot;阿吉特、唐、罗德、布拉德和约翰都不到45岁——这个令人尴尬的事实推翻了我关于管理者只有在70岁以后才能进入最佳状态的理论。&quot;</p></blockquote><h2 id="关联年份" tabindex="-1">关联年份 <a class="header-anchor" href="#关联年份" aria-label="Permalink to &quot;关联年份&quot;">​</a></h2><p>1988, 1989, 1993, 1994, 1995, 1996, 1997</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./../03_公司库/伯克希尔哈撒韦.html">伯克希尔·哈撒韦</a> - 母公司</li><li><a href="./查理·芒格.html">查理·芒格</a> - 副董事长</li><li><a href="./伯克希尔管理层/迈克·戈德堡.html">迈克·戈德堡</a> - 引荐人</li></ul><hr><p><em>最后更新：2026-04-09</em></p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/1989年/翻译.html">1989年</a></li><li><a href="./../01_letters/1993年/翻译.html">1993年</a></li><li><a href="./../01_letters/1994年/翻译.html">1994年</a></li><li><a href="./../01_letters/1995年/翻译.html">1995年</a></li><li><a href="./../01_letters/1996年/翻译.html">1996年</a></li><li><a href="./../01_letters/1999年/翻译.html">1999年</a></li><li><a href="./../01_letters/2004年/翻译.html">2004年</a></li><li><a href="./../01_letters/2006年/翻译.html">2006年</a></li><li><a href="./../01_letters/2007年/翻译.html">2007年</a></li><li><a href="./../01_letters/2008年/翻译.html">2008年</a></li><li><a href="./../01_letters/2009年/翻译.html">2009年</a></li><li><a href="./../01_letters/2011年/翻译.html">2011年</a></li><li><a href="./../01_letters/2017年/翻译.html">2017年</a></li><li><a href="./../01_letters/2020年/翻译.html">2020年</a></li><li><a href="./../01_letters/2025年/翻译.html">2025年</a></li></ul>',27)])])}const c=a(o,[["render",i]]);export{_ as __pageData,c as default};
